import{_ as t,o as e,c as r,a2 as o}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/6903_巨漢/20260502/G03_核心員工流動率審計_績效管理專家.md","filePath":"審計報告庫/經營審計/6903_巨漢/20260502/G03_核心員工流動率審計_績效管理專家.md"}'),i={name:"審計報告庫/經營審計/6903_巨漢/20260502/G03_核心員工流動率審計_績效管理專家.md"};function l(n,a,_,s,h,d){return e(),r("div",null,[...a[0]||(a[0]=[o('<h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>核心技術或研發團隊的流動率為何？公司如何留住優秀人才？是否有關鍵人才流向競爭對手的跡象？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>巨漢身為工程統包業，核心資產為工程師團隊（約 200-300 人）。近 2 年無大量離職或高層出走消息，員工穩定度高。惟工程業人才競爭激烈（半導體廠擴產潮推升薪資），留才壓力上升。人均產值約 1,000-1,500 萬，優於同業。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>A-（良）。無異常離職或高層出走，員工穩定度佳。利空：2025 年營收暴增 72.8%，但員工人數未等比增加，現有團隊可能超載，過勞風險將導致流動率上升。半導體擴產潮推升同業薪資，留才成本增加將壓縮獲利。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><ol><li><p><strong>員工概況</strong>：估計員工人數約 200-300 人（2023 年 IPO 時揭露約 200 人，隨業務擴張應有增加）。人均產值約 1,000-1,500 萬，高於營造業平均（約 500-800 萬），顯示人力運用效率優異。</p></li><li><p><strong>留才機制</strong>：員工薪酬約佔營收 4%（約 1.2-1.4 億），含年終獎金與績效分紅。2023 年 IPO 後有員工認股權憑證，可留住關鍵人才。無大規模離職或跳槽同業的消息。</p></li><li><p><strong>流動率估算</strong>：從公開資訊推測，年離職率約 10-15%，在工程業屬正常水準。無集體跳槽或整批被挖角的事件。核心主管（總經理、副總經理）均已在職 5 年以上，管理層穩定。</p></li></ol><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><ol><li><strong>過勞風險</strong>：營收 +72.8% 但人力未等比擴充，團隊可能已超載。若長期加班將導致 burnout，核心工程師可能被同業高薪挖角。需關注人均產值是否已達極限。</li><li><strong>薪資競爭力</strong>：半導體擴產潮帶動同業（帆宣、聖暉）調薪搶人，巨漢的薪酬水準若不具競爭力，關鍵人才可能流失。目前營收 31.77 億、薪資費用約 1.4 億，用人成本佔比 4.4%，尚在合理範圍。</li><li><strong>接班深度不足</strong>：總經理以下的中階主管名單未揭露，接班人梯隊不明確。若現有主管離職，內部能否迅速遞補仍是未知。相較於財務健全度，人才儲備的透明度偏低。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>web_search：巨漢 6903 員工福利費用、員工人數</li><li>FinMind：TaiwanStockFinancialStatements（員工福利費用估算）</li></ul>',12)])])}const u=t(i,[["render",l]]);export{p as __pageData,u as default};
